23	  subject: z.string().min(3, "Please add a subject"),
24	  message: z.string().min(10, "Please add a bit more detail"),
25	});
26	
27	const SUBJECT_PRESETS: Record<string, { label: string; preset: string }> = {
28	  partnership: { label: "Strategic Partnership", preset: "Partnership inquiry" },
29	  partner: { label: "Strategic Partnership", preset: "Partnership inquiry" },
30	  buyer: { label: "Buy a Pegasus Home", preset: "Interested in a renovated home" },
31	  contractor: { label: "Contractor & Trades", preset: "Contractor / trade introduction" },
32	  development: { label: "Development Project", preset: "Development project inquiry" },
33	  investments: { label: "Investments / Capital", preset: "Investment partnership inquiry" },
34	  systems: { label: "Pegasus Systems", preset: "Pegasus Systems inquiry" },
35	  "marketflow-access": {
36	    label: "MarketFlow Beta Access",
37	    preset: "Request MarketFlow beta access",
38	  },
39	};
40	
41	function useSubjectPreset(): { label?: string; preset?: string } {
42	  if (typeof window === "undefined") return {};
43	  const params = new URLSearchParams(window.location.search);
44	  const subject = params.get("subject");
45	  if (!subject) return {};
46	  return SUBJECT_PRESETS[subject] ?? {};
47	}
