@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* PEGASUS DREAMSCAPES - Brand-Aligned Premium Theme */
/* Brand Colors: Navy Wings, Copper Horse, Cream Background */
:root {
  --button-outline: rgba(0,0,0, .08);
  --badge-outline: rgba(0,0,0, .04);
  --opaque-button-border-intensity: -6;
  --elevate-1: rgba(0,0,0, .02);
  --elevate-2: rgba(0,0,0, .05);
  --background: 38 28% 97%;
  --foreground: 215 55% 18%;
  --border: 35 18% 86%;
  --card: 0 0% 100%;
  --card-foreground: 215 55% 18%;
  --card-border: 35 12% 88%;
  --tan: 35 35% 70%;
  --tan-foreground: 215 55% 18%;
  --champagne: 38 40% 88%;
  --champagne-foreground: 215 55% 18%;
  --warm-glow: 22 80% 55%;
  --stone: 38 20% 95%;
  --stone-foreground: 215 55% 18%;
  --navy: 215 65% 25%;
  --navy-foreground: 0 0% 100%;
  --copper: 22 78% 50%;
  --copper-foreground: 0 0% 100%;
  --sidebar: 38 22% 96%;
  --sidebar-foreground: 215 55% 18%;
  --sidebar-border: 35 15% 88%;
  --sidebar-primary: 22 78% 48%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 38 18% 93%;
  --sidebar-accent-foreground: 215 55% 20%;
  --sidebar-ring: 22 78% 48%;
  --popover: 0 0% 100%;
  --popover-foreground: 215 55% 18%;
  --popover-border: 35 12% 88%;
  --primary: 22 78% 48%;
  --primary-foreground: 0 0% 100%;
  --secondary: 215 65% 25%;
  --secondary-foreground: 0 0% 100%;
  --muted: 38 15% 95%;
  --muted-foreground: 215 30% 40%;
  --accent: 22 78% 48%;
  --accent-foreground: 0 0% 100%;
  --destructive: 0 65% 50%;
  --destructive-foreground: 0 0% 100%;
  --input: 38 15% 91%;
  --ring: 22 78% 48%;
  --chart-1: 22 78% 50%;
  --chart-2: 215 55% 35%;
  --chart-3: 35 40% 50%;
  --chart-4: 215 45% 28%;
  --chart-5: 22 65% 42%;
  --font-sans: 'Inter', system-ui, sans-serif;
  --font-serif: 'Playfair Display', Georgia, serif;
  --font-mono: Menlo, monospace;
  --radius: .375rem;
  --shadow-2xs: 0 1px 2px 0 hsl(0 0% 0% / 0.03);
  --shadow-xs: 0 1px 3px 0 hsl(0 0% 0% / 0.04);
  --shadow-sm: 0 2px 4px -1px hsl(0 0% 0% / 0.05), 0 1px 2px -1px hsl(0 0% 0% / 0.03);
  --shadow: 0 4px 6px -2px hsl(0 0% 0% / 0.05), 0 2px 4px -1px hsl(0 0% 0% / 0.03);
  --shadow-md: 0 6px 12px -3px hsl(0 0% 0% / 0.08), 0 3px 6px -2px hsl(0 0% 0% / 0.04);
  --shadow-lg: 0 12px 24px -4px hsl(0 0% 0% / 0.10), 0 4px 8px -2px hsl(0 0% 0% / 0.04);
  --shadow-xl: 0 20px 40px -8px hsl(0 0% 0% / 0.12), 0 8px 16px -4px hsl(0 0% 0% / 0.05);
  --shadow-2xl: 0 32px 64px -12px hsl(0 0% 0% / 0.15);
  --tracking-normal: 0em;
  --spacing: 0.25rem;

/* Fallback for older browsers */
  --sidebar-primary-border: hsl(var(--sidebar-primary));
  --sidebar-primary-border: hsl(from hsl(var(--sidebar-primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  /* Fallback for older browsers */
  --sidebar-accent-border: hsl(var(--sidebar-accent));

