  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { 
  Menu, 
  X, 
  ChevronDown, 
  Calculator, 
  TrendingUp, 
  Home,
  DollarSign,
  BookOpen,
